import json

file_path = locals()['var_function-call-17204198611031670193']
with open(file_path, 'r') as f:
    data = json.load(f)

top_names = ["@docly/web", "@dylanvann/svelte", "@dumc11/tailwindcss", "@dynasty/styled-components", "@dothq/styled-components"]
latest_versions = {}

for row in data:
    name = row['Name']
    ver = row['Version']
    # UpstreamPublishedAt is a string in the JSON output, need to convert to float
    ts = float(row['UpstreamPublishedAt'])

    if name not in latest_versions or ts > latest_versions[name]['ts']:
        latest_versions[name] = {'ver': ver, 'ts': ts}

results = []
for name in top_names:
    if name in latest_versions:
        results.append((name, latest_versions[name]['ver']))
    else:
        results.append((name, "Unknown"))

print("__RESULT__:")
print(json.dumps(results))

